import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { Router, RouterModule } from '@angular/router';
import { AuthService } from '../../core/services/auth.service';
import { UserProfile } from '../../core/models/user-profile.model';

@Component({
  selector: 'app-dashboard',
  standalone: true,
  imports: [
    CommonModule,
    RouterModule
  ],
  templateUrl: './dashboard.component.html',
  styleUrls: ['./dashboard.component.css']
})

export class DashboardComponent implements OnInit {

  private authService = inject(AuthService);
  private router = inject(Router);

  profile: UserProfile | null = null;
  isLoading = true;
  errorMsg = '';

  ngOnInit(): void {
    this.authService.getProfile().subscribe({
      next: (user) => {
        this.profile = user;
        this.isLoading = false;
      },
      error: (err) => {
        this.isLoading = false;
        this.errorMsg = 'No se pudo cargar el perfil del usuario autenticado.';
      }
    });
  }

  onLogout(): void {
    this.authService.logout();
    this.router.navigate(['/login']);
  }
}
<div class="dashboard-container">
  <header class="dashboard-header">
    <div class="logo-container">
      <div class="logo-icon">I</div>
      <span class="logo-text">INSTEIP</span>
    </div>
    <button class="logout-btn" (click)="onLogout()">
      <span class="material-symbols-outlined text-sm">logout</span>
      <span>Cerrar Sesión</span>
    </button>
  </header>

  <main class="dashboard-content">
    @if (isLoading) {
      <div class="loading-state">
        <span class="material-symbols-outlined spin-icon text-4xl">sync</span>
        <p>Cargando información del perfil...</p>
      </div>
    } @else if (errorMsg) {
      <div class="error-alert">
        <span class="material-symbols-outlined text-2xl">error_outline</span>
        <span>{{ errorMsg }}</span>
      </div>
    } @else if (profile) {
      <div class="dashboard-grid">
        <!-- Tarjeta de Perfil -->
        <div class="profile-card">
          <div class="flex items-center gap-4 mb-6">
            <div class="profile-avatar">
              {{ profile.nombres.charAt(0) }}{{ profile.apellidos.charAt(0) }}
            </div>
            <div>
              <h3 class="profile-title">{{ profile.nombres }} {{ profile.apellidos }}</h3>
              <p class="profile-subtitle">{{ profile.rol }}</p>
            </div>
          </div>

          <div class="profile-details">
            <div class="detail-row">
              <span class="detail-label">Correo electrónico</span>
              <span class="detail-value">{{ profile.correo }}</span>
            </div>
            <div class="detail-row">
              <span class="detail-label">Identificador de Usuario</span>
              <span class="detail-value">ID-{{ profile.id }}</span>
            </div>
            <div class="detail-row">
              <span class="detail-label">Nivel de Privilegios</span>
              <span class="detail-value highlight-rol">{{ profile.rol }}</span>
            </div>
          </div>
        </div>

        <!-- Tarjeta de Bienvenida y Estado -->
        <div class="welcome-board">
          <h1 class="welcome-title">¡Bienvenido de vuelta, {{ profile.nombres }}!</h1>
          <p class="welcome-text">Has iniciado sesión correctamente. La infraestructura de autenticación de la FASE 1 está completamente operativa y asegurada.</p>

          <div class="tech-badges">
            <span class="badge jpa">Spring Boot 3.4</span>
            <span class="badge security">Spring Security</span>
            <span class="badge jwt">JWT (jjwt)</span>
            <span class="badge angular">Angular 20</span>
          </div>

          <div class="status-connection">
            <span class="material-symbols-outlined text-xl">verified_user</span>
            <span>Sesión activa mediante autenticación stateless y firma JWT verificada</span>
          </div>
        </div>
      </div>
    }
  </main>
</div>
